#!/usr/bin/env python3
"""Map every Python test file to the production module(s) it imports.

Output: JSON list of {test_file, n_tests, prod_imports[], primary_target, prod_file}.
primary_target/prod_file is the best mutation target (name match -> most-imported).
Run from repo root: python inventory.py apps/api app  (test_root, prod_pkg)
"""

from __future__ import annotations

import ast
import json
import sys
from pathlib import Path


def module_to_file(mod: str, app_root: Path) -> Path | None:
    """app.services.search_service -> apps/api/app/services/search_service.py"""
    rel = Path(*mod.split("."))
    cand = app_root.parent / rel.with_suffix(".py")
    if cand.exists():
        return cand
    pkg = app_root.parent / rel / "__init__.py"
    return pkg if pkg.exists() else None


def collect(test_file: Path, prod_pkg: str, app_root: Path) -> dict:
    src = test_file.read_text(encoding="utf-8", errors="replace")
    try:
        tree = ast.parse(src)
    except SyntaxError:
        return {"test_file": str(test_file), "error": "syntax", "n_tests": 0,
                "prod_imports": [], "primary_target": None, "prod_file": None}

    n_tests = sum(
        isinstance(n, (ast.FunctionDef, ast.AsyncFunctionDef)) and n.name.startswith("test_")
        for n in ast.walk(tree)
    )

    prod_mods: list[str] = []
    for node in ast.walk(tree):
        if isinstance(node, ast.ImportFrom) and node.module and node.module.split(".")[0] == prod_pkg:
            prod_mods.append(node.module)
        elif isinstance(node, ast.Import):
            for a in node.names:
                if a.name.split(".")[0] == prod_pkg:
                    prod_mods.append(a.name)

    # Resolve to files, dedup preserving order.
    seen: dict[str, Path] = {}
    for m in prod_mods:
        f = module_to_file(m, app_root)
        if f and m not in seen:
            seen[m] = f

    # Primary target: prefer a prod module whose file stem matches the test stem
    # (test_weather_tool -> weather_tool.py), else the deepest-named import.
    stem = test_file.stem.removeprefix("test_").removesuffix("_test")
    primary_mod, primary_file = None, None
    for m, f in seen.items():
        if f.stem == stem:
            primary_mod, primary_file = m, f
            break
    if not primary_file and seen:
        primary_mod = max(seen, key=lambda m: len(m.split(".")))
        primary_file = seen[primary_mod]

    return {
        "test_file": str(test_file),
        "n_tests": n_tests,
        "prod_imports": sorted(seen),
        "primary_target": primary_mod,
        "prod_file": str(primary_file) if primary_file else None,
    }


def main() -> int:
    test_root = Path(sys.argv[1]).resolve()       # apps/api
    prod_pkg = sys.argv[2] if len(sys.argv) > 2 else "app"
    app_root = test_root / prod_pkg                 # apps/api/app

    rows = []
    for tf in sorted(test_root.rglob("test_*.py")):
        if "/tests/" not in str(tf) and "/test/" not in str(tf):
            continue
        rows.append(collect(tf, prod_pkg, app_root))

    no_target = [r for r in rows if not r["prod_file"]]
    print(json.dumps({
        "test_root": str(test_root),
        "total_test_files": len(rows),
        "total_test_funcs": sum(r["n_tests"] for r in rows),
        "files_without_prod_target": len(no_target),
        "rows": rows,
    }, indent=2))
    return 0


if __name__ == "__main__":
    raise SystemExit(main())

