export const meta = {
  name: 'test-overhaul-patch',
  description: 'Parallel patch wave: for files below their mutation kill-gate, add/strengthen tests to kill surviving mutants. Same tree, disjoint test files.',
  phases: [{ title: 'Patch' }],
}

// args = { items: [{prod_file, test_file, tier, gate, kill_rate, survivors:[{lineno,kind,mutation}]}] }
const PRIMARY = '/Users/aryan/Projects/GAIA/gaia'
const API = `${PRIMARY}/apps/api`
const VENVPY = `${PRIMARY}/.venv/bin/python`
const MUTATE = `${PRIMARY}/.agents/plans/test-overhaul/mutate.py`
const RUBRIC = `${PRIMARY}/.agents/plans/test-overhaul/RUBRIC.md`
const OUT = `${PRIMARY}/.agents/plans/test-overhaul/results`

const A = typeof args === 'string' ? JSON.parse(args) : args || {}
const items = A && Array.isArray(A.items) ? A.items : []
log(`patch wave: ${items.length} below-gate files`)
if (!items.length) return { error: 'no items' }

const SCHEMA = {
  type: 'object',
  additionalProperties: false,
  required: ['test_file', 'kill_before', 'kill_after', 'gate_met', 'green', 'summary'],
  properties: {
    test_file: { type: 'string' },
    kill_before: { type: 'number' },
    kill_after: { type: 'number' },
    gate_met: { type: 'boolean' },
    green: { type: 'boolean' },
    equivalent_survivors: { type: 'array', items: { type: 'string' } },
    summary: { type: 'string' },
  },
}

function prompt(t) {
  const mongo = ['service', 'services', 'integration', 'db', 'mcp', 'vfs', 'agents', 'api'].includes(t.tier)
    ? `MONGODB_URL=mongodb://localhost:27017/gaia_test ` : ''
  const survList = (t.survivors || []).map((s) => `  - L${s.lineno} ${s.kind}: ${s.mutation}`).join('\n') || '  (none recorded — discover via mutate.py)'
  return `You are closing the mutation-coverage gap on ONE test file. Work in ${API}. Parallel with other agents on OTHER files — touch only YOUR target.

TARGET
- Production unit: ${t.prod_file}
- Test file: ${t.test_file}   Tier: ${t.tier}   Kill-gate: ${t.gate}   Current kill_rate: ${t.kill_rate}

SURVIVING MUTANTS the current tests FAIL to catch (each is a real, uncaught regression — your job is to make the tests catch them):
${survList}

ENV RULES (parallel-safe shared tree)
- Use \`${VENVPY} -m pytest ...\` and \`${VENVPY} ${MUTATE} ...\` directly. NEVER \`uv run\`.
- Prefix DB-tier commands with: ${mongo || '(no MONGODB_URL needed)'}
- Edit ONLY ${t.test_file}. Do NOT edit production code.

STEPS
1. Read RUBRIC (${RUBRIC}), the production unit (${API}/${t.prod_file}), and the current test (${API}/${t.test_file}).
2. For EACH surviving mutant, add or strengthen a test that asserts the real behavior the mutant breaks (e.g. a flipped comparison, a wrong constant, a dropped return). Assert real outcomes — never assert-called-only, never escape-hatch \`or\`. If a survivor is a genuine EQUIVALENT mutant (behavior-preserving — prove it, don't assume), record it in equivalent_survivors with the proof and move on.
3. Verify (REQUIRED):
   a. Green isolated: \`${mongo}${VENVPY} -m pytest ${t.test_file} -q -n0 -p no:cacheprovider --no-header\`
   b. Green parallel: \`${mongo}${VENVPY} -m pytest ${t.test_file} -q\`
   c. Mutation: \`${mongo}${VENVPY} ${MUTATE} ${t.prod_file} --tests ${t.test_file} --root . --quiet\` → kill_rate >= ${t.gate} (or every remaining survivor justified equivalent). LOOP on survivors until met.
4. Stage: \`mkdir -p ${OUT}\`; write \`${OUT}/<test_file__mangled>.patch.json\` with your final result.
Return the structured result. gate_met=true only if kill_rate >= gate or all survivors proven equivalent.`
}

const results = await parallel(
  items.map((t) => () =>
    agent(prompt(t), { label: `patch:${t.test_file.split('/').pop()}`, phase: 'Patch', schema: SCHEMA }).catch(() => null)
  )
)
const ok = results.filter(Boolean)
return {
  processed: items.length,
  gate_met: ok.filter((r) => r.gate_met).length,
  still_below: ok.filter((r) => !r.gate_met).length,
  results: ok,
}

